import ApolloClient from 'apollo-client';
import { InMemoryCache } from 'apollo-cache-inmemory';
import { createHttpLink } from 'apollo-link-http';

const client = new ApolloClient({
    link: createHttpLink({ uri: 'https://api.ftcscout.org/graphql' }),
    cache: new InMemoryCache(),
});

// GraphQL Queries
export const GET_EVENT_DETAILS = `
    query GetEventDetails($eventId: ID!) {
        event(id: $eventId) {
            name
            location
            date
            matches {
                id
                redAlliance {
                    teamNumber
                    opr
                }
                blueAlliance {
                    teamNumber
                    opr
                }
            }
        }
    }
`;

export const GET_MATCH_SCHEDULE = `
    query GetMatchSchedule($eventId: ID!) {
        event(id: $eventId) {
            matches {
                id
                redAlliance {
                    teamNumber
                }
                blueAlliance {
                    teamNumber
                }
            }
        }
    }
`;

export const GET_TEAM_STATISTICS = `
    query GetTeamStatistics($teamNumber: Int!) {
        team(number: $teamNumber) {
            wins
            losses
            opr
        }
    }
`;

export const fetchEventDetails = async (eventId) => {
    const { data } = await client.query({
        query: GET_EVENT_DETAILS,
        variables: { eventId },
    });
    return data.event;
};

export const fetchMatchSchedule = async (eventId) => {
    const { data } = await client.query({
        query: GET_MATCH_SCHEDULE,
        variables: { eventId },
    });
    return data.event.matches;
};

export const fetchTeamStatistics = async (teamNumber) => {
    const { data } = await client.query({
        query: GET_TEAM_STATISTICS,
        variables: { teamNumber },
    });
    return data.team;
};

export const fetchEventData = async (eventName) => {
    // This is a wrapper function that searches for an event by name
    // For now, it returns mock data - in a real app, you'd need to search the API
    return {
        name: eventName,
        location: 'Location TBD',
        date: 'Date TBD',
        matches: [],
    };
};
